import{_ as e,o as a,c as d,ae as i}from"./chunks/framework.C7FLYIpo.js";const k=JSON.parse('{"title":"이미지 생성","description":"구성된 프로바이더를 사용하여 이미지를 생성하고 편집 (OpenAI, Google Gemini, fal, MiniMax, ComfyUI, Vydra)","frontmatter":{"title":"이미지 생성","description":"구성된 프로바이더를 사용하여 이미지를 생성하고 편집 (OpenAI, Google Gemini, fal, MiniMax, ComfyUI, Vydra)"},"headers":[],"relativePath":"tools/image-generation.md","filePath":"tools/image-generation.md","lastUpdated":null}'),s={name:"tools/image-generation.md"};function o(n,t,l,c,r,p){return a(),d("div",null,[...t[0]||(t[0]=[i(`<h1 id="이미지-생성" tabindex="-1">이미지 생성 <a class="header-anchor" href="#이미지-생성" aria-label="Permalink to &quot;이미지 생성&quot;">​</a></h1><p><code>image_generate</code> 도구를 사용하면 에이전트가 구성된 프로바이더를 사용하여 이미지를 생성하고 편집할 수 있습니다. 생성된 이미지는 에이전트 응답에서 미디어 첨부 파일로 자동 전달됩니다.</p><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>이 도구는 적어도 하나의 이미지 생성 프로바이더를 사용할 수 있을 때만 나타납니다. 에이전트 도구에서 <code>image_generate</code>가 보이지 않으면 <code>agents.defaults.imageGenerationModel</code>을 구성하거나 프로바이더 API 키를 설정하십시오.</p></div><h2 id="빠른-시작" tabindex="-1">빠른 시작 <a class="header-anchor" href="#빠른-시작" aria-label="Permalink to &quot;빠른 시작&quot;">​</a></h2><ol><li>적어도 하나의 프로바이더에 대한 API 키를 설정합니다 (예: <code>OPENAI_API_KEY</code> 또는 <code>GEMINI_API_KEY</code>).</li><li>선택적으로 선호하는 모델을 설정합니다:</li></ol><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  agents</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    defaults</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      imageGenerationModel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        primary</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;openai/gpt-image-1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><ol start="3"><li>에이전트에 요청합니다: <em>&quot;Generate an image of a friendly lobster mascot.&quot;</em></li></ol><p>에이전트는 자동으로 <code>image_generate</code>를 호출합니다. 도구 허용 목록 추가가 필요하지 않습니다. 프로바이더를 사용할 수 있을 때 기본적으로 활성화됩니다.</p><h2 id="지원-프로바이더" tabindex="-1">지원 프로바이더 <a class="header-anchor" href="#지원-프로바이더" aria-label="Permalink to &quot;지원 프로바이더&quot;">​</a></h2><table tabindex="0"><thead><tr><th>프로바이더</th><th>기본 모델</th><th>편집 지원</th><th>API 키</th></tr></thead><tbody><tr><td>OpenAI</td><td><code>gpt-image-1</code></td><td>Yes (최대 5개 이미지)</td><td><code>OPENAI_API_KEY</code></td></tr><tr><td>Google</td><td><code>gemini-3.1-flash-image-preview</code></td><td>Yes</td><td><code>GEMINI_API_KEY</code> 또는 <code>GOOGLE_API_KEY</code></td></tr><tr><td>fal</td><td><code>fal-ai/flux/dev</code></td><td>Yes</td><td><code>FAL_KEY</code></td></tr><tr><td>MiniMax</td><td><code>image-01</code></td><td>Yes (주제 참조)</td><td><code>MINIMAX_API_KEY</code> 또는 MiniMax OAuth (<code>minimax-portal</code>)</td></tr><tr><td>ComfyUI</td><td><code>workflow</code></td><td>Yes (이미지 1개, 워크플로우 구성)</td><td><code>COMFY_API_KEY</code> 또는 클라우드용 <code>COMFY_CLOUD_API_KEY</code></td></tr><tr><td>Vydra</td><td><code>grok-imagine</code></td><td>No</td><td><code>VYDRA_API_KEY</code></td></tr></tbody></table><p>런타임에 사용 가능한 프로바이더와 모델을 검사하려면 <code>action: &quot;list&quot;</code>를 사용하십시오:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/tool image_generate action=list</span></span></code></pre></div><h2 id="도구-파라미터" tabindex="-1">도구 파라미터 <a class="header-anchor" href="#도구-파라미터" aria-label="Permalink to &quot;도구 파라미터&quot;">​</a></h2><table tabindex="0"><thead><tr><th>파라미터</th><th>유형</th><th>설명</th></tr></thead><tbody><tr><td><code>prompt</code></td><td>string</td><td>이미지 생성 프롬프트 (<code>action: &quot;generate&quot;</code>에 필수)</td></tr><tr><td><code>action</code></td><td>string</td><td><code>&quot;generate&quot;</code> (기본값) 또는 프로바이더 검사를 위한 <code>&quot;list&quot;</code></td></tr><tr><td><code>model</code></td><td>string</td><td>프로바이더/모델 재정의, 예: <code>openai/gpt-image-1</code></td></tr><tr><td><code>image</code></td><td>string</td><td>편집 모드를 위한 단일 참조 이미지 경로 또는 URL</td></tr><tr><td><code>images</code></td><td>string[]</td><td>편집 모드를 위한 여러 참조 이미지 (최대 5개)</td></tr><tr><td><code>size</code></td><td>string</td><td>크기 힌트: <code>1024x1024</code>, <code>1536x1024</code>, <code>1024x1536</code>, <code>1024x1792</code>, <code>1792x1024</code></td></tr><tr><td><code>aspectRatio</code></td><td>string</td><td>종횡비: <code>1:1</code>, <code>2:3</code>, <code>3:2</code>, <code>3:4</code>, <code>4:3</code>, <code>4:5</code>, <code>5:4</code>, <code>9:16</code>, <code>16:9</code>, <code>21:9</code></td></tr><tr><td><code>resolution</code></td><td>string</td><td>해상도 힌트: <code>1K</code>, <code>2K</code>, 또는 <code>4K</code></td></tr><tr><td><code>count</code></td><td>number</td><td>생성할 이미지 수 (1-4)</td></tr><tr><td><code>filename</code></td><td>string</td><td>출력 파일명 힌트</td></tr></tbody></table><p>모든 프로바이더가 모든 파라미터를 지원하는 것은 아닙니다. 폴백 프로바이더가 정확히 요청된 것 대신 근접한 기하학 옵션을 지원하는 경우 OpenClaw는 제출 전에 가장 가까운 지원 크기, 종횡비, 또는 해상도로 다시 매핑합니다. 진정으로 지원되지 않는 재정의는 도구 결과에서 계속 보고됩니다.</p><p>도구 결과는 적용된 설정을 보고합니다. OpenClaw가 프로바이더 폴백 중 기하학을 다시 매핑하는 경우, 반환된 <code>size</code>, <code>aspectRatio</code>, <code>resolution</code> 값은 실제로 전송된 내용을 반영하고 <code>details.normalization</code>은 요청-적용 변환을 캡처합니다.</p><h2 id="설정" tabindex="-1">설정 <a class="header-anchor" href="#설정" aria-label="Permalink to &quot;설정&quot;">​</a></h2><h3 id="모델-선택" tabindex="-1">모델 선택 <a class="header-anchor" href="#모델-선택" aria-label="Permalink to &quot;모델 선택&quot;">​</a></h3><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  agents</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    defaults</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      imageGenerationModel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        primary</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;openai/gpt-image-1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        fallbacks</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;google/gemini-3.1-flash-image-preview&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;fal/fal-ai/flux/dev&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="프로바이더-선택-순서" tabindex="-1">프로바이더 선택 순서 <a class="header-anchor" href="#프로바이더-선택-순서" aria-label="Permalink to &quot;프로바이더 선택 순서&quot;">​</a></h3><p>이미지를 생성할 때 OpenClaw는 다음 순서로 프로바이더를 시도합니다:</p><ol><li>도구 호출의 <strong><code>model</code> 파라미터</strong> (에이전트가 하나를 지정하는 경우)</li><li>설정의 <strong><code>imageGenerationModel.primary</code></strong></li><li>순서대로 <strong><code>imageGenerationModel.fallbacks</code></strong></li><li><strong>자동 감지</strong> — 인증 기반 프로바이더 기본값만 사용: <ul><li>현재 기본 프로바이더 먼저</li><li>나머지 등록된 이미지 생성 프로바이더를 프로바이더 ID 순서로</li></ul></li></ol><p>프로바이더가 실패하면 (인증 오류, 속도 제한 등) 다음 후보가 자동으로 시도됩니다. 모두 실패하면 오류에 각 시도의 세부 정보가 포함됩니다.</p><p>참고 사항:</p><ul><li>자동 감지는 인증을 인식합니다. 프로바이더 기본값은 OpenClaw가 실제로 해당 프로바이더를 인증할 수 있는 경우에만 후보 목록에 들어갑니다.</li><li>자동 감지는 기본적으로 활성화됩니다. 이미지 생성이 명시적 <code>model</code>, <code>primary</code>, <code>fallbacks</code> 항목만 사용하도록 하려면 <code>agents.defaults.mediaGenerationAutoProviderFallback: false</code>를 설정하십시오.</li><li>현재 등록된 프로바이더, 기본 모델, 인증 환경 변수 힌트를 검사하려면 <code>action: &quot;list&quot;</code>를 사용하십시오.</li></ul><h3 id="이미지-편집" tabindex="-1">이미지 편집 <a class="header-anchor" href="#이미지-편집" aria-label="Permalink to &quot;이미지 편집&quot;">​</a></h3><p>OpenAI, Google, fal, MiniMax, ComfyUI는 참조 이미지 편집을 지원합니다. 참조 이미지 경로 또는 URL을 전달하십시오:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;Generate a watercolor version of this photo&quot; + image: &quot;/path/to/photo.jpg&quot;</span></span></code></pre></div><p>OpenAI와 Google은 <code>images</code> 파라미터를 통해 최대 5개의 참조 이미지를 지원합니다. fal, MiniMax, ComfyUI는 1개를 지원합니다.</p><p>MiniMax 이미지 생성은 두 가지 번들 MiniMax 인증 경로 모두를 통해 사용할 수 있습니다:</p><ul><li>API 키 설정의 경우 <code>minimax/image-01</code></li><li>OAuth 설정의 경우 <code>minimax-portal/image-01</code></li></ul><h2 id="프로바이더-기능" tabindex="-1">프로바이더 기능 <a class="header-anchor" href="#프로바이더-기능" aria-label="Permalink to &quot;프로바이더 기능&quot;">​</a></h2><table tabindex="0"><thead><tr><th>기능</th><th>OpenAI</th><th>Google</th><th>fal</th><th>MiniMax</th><th>ComfyUI</th><th>Vydra</th></tr></thead><tbody><tr><td>생성</td><td>Yes (최대 4개)</td><td>Yes (최대 4개)</td><td>Yes (최대 4개)</td><td>Yes (최대 9개)</td><td>Yes (워크플로우 정의 출력)</td><td>Yes (1)</td></tr><tr><td>편집/참조</td><td>Yes (최대 5개 이미지)</td><td>Yes (최대 5개 이미지)</td><td>Yes (1개 이미지)</td><td>Yes (1개 이미지, 주제 참조)</td><td>Yes (1개 이미지, 워크플로우 구성)</td><td>No</td></tr><tr><td>크기 제어</td><td>Yes</td><td>Yes</td><td>Yes</td><td>No</td><td>No</td><td>No</td></tr><tr><td>종횡비</td><td>No</td><td>Yes</td><td>Yes (생성만 해당)</td><td>Yes</td><td>No</td><td>No</td></tr><tr><td>해상도 (1K/2K/4K)</td><td>No</td><td>Yes</td><td>Yes</td><td>No</td><td>No</td><td>No</td></tr></tbody></table><h2 id="관련-항목" tabindex="-1">관련 항목 <a class="header-anchor" href="#관련-항목" aria-label="Permalink to &quot;관련 항목&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/tools">도구 개요</a> — 모든 사용 가능한 에이전트 도구</li><li><a href="/openclaw-docs-ko/providers/fal">fal</a> — fal 이미지 및 비디오 프로바이더 설정</li><li><a href="/openclaw-docs-ko/providers/comfy">ComfyUI</a> — 로컬 ComfyUI 및 Comfy Cloud 워크플로우 설정</li><li><a href="/openclaw-docs-ko/providers/google">Google (Gemini)</a> — Gemini 이미지 프로바이더 설정</li><li><a href="/openclaw-docs-ko/providers/minimax">MiniMax</a> — MiniMax 이미지 프로바이더 설정</li><li><a href="/openclaw-docs-ko/providers/openai">OpenAI</a> — OpenAI 이미지 프로바이더 설정</li><li><a href="/openclaw-docs-ko/providers/vydra">Vydra</a> — Vydra 이미지, 비디오, 음성 설정</li><li><a href="/openclaw-docs-ko/gateway/configuration-reference#agent-defaults">설정 레퍼런스</a> — <code>imageGenerationModel</code> 설정</li><li><a href="/openclaw-docs-ko/concepts/models">모델</a> — 모델 설정 및 장애 조치</li></ul>`,35)])])}const g=e(s,[["render",o]]);export{k as __pageData,g as default};
